// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  // Get weather icon/emoji based on condition
  const getWeatherIcon = (condition: string) => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloudy')) return '☁️';
    if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snowy') || conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('stormy') || conditionLower.includes('storm')) return '⛈️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('foggy') || conditionLower.includes('fog')) return '🌫️';
    return '🌤️'; // Default fallback
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" border>
          <Stack gap="var(--ggui-spacing-4)">
            {/* Header: City and Condition */}
            <Stack direction="horizontal" align="center" justify="between">
              <Stack gap="var(--ggui-spacing-2)" align="start">
                <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  {props.condition}
                </Text>
              </Stack>
              <Box fontSize="3rem" lineHeight="1">
                {getWeatherIcon(props.condition)}
              </Box>
            </Stack>

            <Divider margin="var(--ggui-spacing-3)" />

            {/* Temperature Section - Large and Prominent */}
            <Box textAlign="center">
              <Text
                as="div"
                style={{
                  fontSize: 'var(--ggui-font-size-4xl)',
                  fontWeight: 'var(--ggui-font-weight-bold)',
                  color: 'var(--ggui-color-primary-600)',
                  lineHeight: 1.2,
                }}
              >
                {props.temperature}°{props.unit}
              </Text>
            </Box>

            <Divider margin="var(--ggui-spacing-3)" />

            {/* Humidity and Wind Speed */}
            <Row gap="var(--ggui-spacing-6)" justify="center" align="center">
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-info-500)" />
                <Stack gap="var(--ggui-spacing-1)" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Humidity
                  </Text>
                  <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">
                    {props.humidity}%
                  </Text>
                </Stack>
              </Stack>

              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" />

              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Icon name="wind" size={24} color="var(--ggui-color-warning-500)" />
                <Stack gap="var(--ggui-spacing-1)" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Wind Speed
                  </Text>
                  <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">
                    {props.windSpeed} m/s
                  </Text>
                </Stack>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast Strip */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="lg" border>
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={4} color="var(--ggui-color-onSurface)">
                5-Day Forecast
              </Heading>

              <Row gap="var(--ggui-spacing-2)" justify="between" align="stretch" wrap>
                {props.forecast.map((day, idx) => (
                  <Card
                    key={idx}
                    shadow="none"
                    padding="var(--ggui-spacing-3)"
                    radius="md"
                    border
                    style={{
                      flex: '1 1 calc(20% - var(--ggui-spacing-2))',
                      minWidth: '100px',
                      textAlign: 'center',
                      background: 'var(--ggui-color-surfaceVariant)',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                      {day.day && (
                        <Text variant="label" color="var(--ggui-color-onSurface)" weight="semibold">
                          {day.day}
                        </Text>
                      )}

                      {day.icon && (
                        <Text style={{ fontSize: '2rem', lineHeight: 1 }}>
                          {day.icon}
                        </Text>
                      )}

                      {(day.high !== undefined || day.low !== undefined) && (
                        <Stack gap="var(--ggui-spacing-1)" align="center">
                          {day.high !== undefined && (
                            <Text variant="bodySmall" color="var(--ggui-color-primary-600)" weight="semibold">
                              {day.high}°
                            </Text>
                          )}
                          {day.low !== undefined && (
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                              {day.low}°
                            </Text>
                          )}
                        </Stack>
                      )}
                    </Stack>
                  </Card>
                ))}
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

