// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper to get priority badge color
function getPriorityVariant(priority?: string): 'success' | 'warning' | 'error' | 'default' {
  switch (priority) {
    case 'low': return 'success';
    case 'medium': return 'warning';
    case 'high': return 'error';
    default: return 'default';
  }
}

// Task Card Component
interface TaskCardProps {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  columns: Array<{ id?: string; name?: string }>;
  onMove: (taskId: string, toColumn: string) => void;
  onEdit: (taskId: string, title: string) => void;
  isEditing: boolean;
  editTitle: string;
  onEditChange: (value: string) => void;
  onEditSave: () => void;
  onEditCancel: () => void;
}

function TaskCard({
  task,
  columns,
  onMove,
  onEdit,
  isEditing,
  editTitle,
  onEditChange,
  onEditSave,
  onEditCancel,
}: TaskCardProps) {
  const otherColumns = columns.filter((col) => col.id !== task.column);

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" border>
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)" direction="horizontal">
            <Input
              label="Edit task"
              value={editTitle}
              onChange={onEditChange}
              onKeyDown={(e) => {
                if (e.key === 'Enter') onEditSave();
                if (e.key === 'Escape') onEditCancel();
              }}
              placeholder="Task title"
              size="sm"
              autoFocus
            />
            <Button size="sm" variant="primary" onClick={onEditSave}>
              Save
            </Button>
            <Button size="sm" variant="ghost" onClick={onEditCancel}>
              Cancel
            </Button>
          </Stack>
        ) : (
          <Box
            as={Clickable}
            onClick={() => onEdit(task.id || '', editTitle)}
            onDoubleClick={() => onEdit(task.id || '', editTitle)}
            role="button"
            tabIndex={0}
            aria-label={`Edit task: ${task.title}`}
            style={{
              padding: 'var(--ggui-spacing-2)',
              borderRadius: 'var(--ggui-shape-radius-md)',
              cursor: 'pointer',
              transition: 'background-color 200ms ease-in-out',
            }}
            onMouseEnter={(e) => {
              (e.currentTarget as HTMLElement).style.backgroundColor = 'var(--ggui-color-surfaceVariant)';
            }}
            onMouseLeave={(e) => {
              (e.currentTarget as HTMLElement).style.backgroundColor = 'transparent';
            }}
          >
            <Text variant="body" weight="semibold" truncate>
              {task.title}
            </Text>
          </Box>
        )}

        <Row gap="var(--ggui-spacing-2)" align="center">
          <Badge variant={getPriorityVariant(task.priority)} size="sm" pill>
            {task.priority || 'none'}
          </Badge>
          {task.assignee && (
            <Avatar name={task.assignee} size="sm" shape="circle" />
          )}
          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" truncate>
              {new Date(task.dueDate).toLocaleDateString()}
            </Text>
          )}
        </Row>

        {otherColumns.length > 0 && (
          <Dropdown
            trigger={<Button variant="outline" size="sm" aria-label="Move task to another column">Move</Button>}
            options={otherColumns.map((col) => ({
              value: col.id || '',
              label: col.name || '',
            }))}
            value=""
            onChange={(colId) => {
              onMove(task.id || '', colId);
            }}
            placement="bottom-end"
          />
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Local state
  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');
  const [showAddFormColumn, setShowAddFormColumn] = useState<string | null>(null);

  // Update tasks from props when they change
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Handle stream updates from other users
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setTasks((prev) => [...prev, task]);
      } else if (action === 'move' && task) {
        setTasks((prev) =>
          prev.map((t) => (t.id === task.id ? { ...t, column: task.column } : t))
        );
      } else if (action === 'edit' && task) {
        setTasks((prev) =>
          prev.map((t) => (t.id === task.id ? { ...t, ...task } : t))
        );
      } else if (action === 'delete' && task) {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = useCallback((taskId: string, toColumn: string) => {
    taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t))
    );
  }, [taskUpdate]);

  const handleEditTaskStart = useCallback((taskId: string) => {
    const task = tasks.find((t) => t.id === taskId);
    if (task) {
      setEditingTaskId(taskId);
      setEditingTitle(task.title || '');
    }
  }, [tasks]);

  const handleEditTaskSave = useCallback(() => {
    if (editingTaskId && editingTitle.trim()) {
      taskUpdate({
        action: 'edit',
        taskId: editingTaskId,
        data: { column: tasks.find((t) => t.id === editingTaskId)?.column || 'todo' },
      });
      setTasks((prev) =>
        prev.map((t) =>
          t.id === editingTaskId ? { ...t, title: editingTitle } : t
        )
      );
      setEditingTaskId(null);
      setEditingTitle('');
    }
  }, [editingTaskId, editingTitle, taskUpdate, tasks]);

  const handleEditTaskCancel = useCallback(() => {
    setEditingTaskId(null);
    setEditingTitle('');
  }, []);

  const handleAddTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: `task-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
        title: newTaskTitle,
        priority: newTaskPriority as 'low' | 'medium' | 'high',
        column: columnId,
        assignee: undefined,
        dueDate: undefined,
      };
      taskUpdate({
        action: 'create',
        taskId: newTask.id,
        data: { column: columnId },
      });
      setTasks((prev) => [...prev, newTask]);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddFormColumn(null);
    }
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  // Computed values
  const completedCount = useMemo(
    () => tasks.filter((t) => t.column === 'done').length,
    [tasks]
  );

  const totalCount = tasks.length;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border background="var(--ggui-color-primary-50)" role="region" aria-label="Task summary">
          <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3} color="var(--ggui-color-primary-700)">
                Task Summary
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">
                {completedCount} of {totalCount} tasks completed
              </Text>
            </Stack>
            <Progress
              label="Task Progress"
              value={totalCount > 0 ? (completedCount / totalCount) * 100 : 0}
              max={100}
              variant="success"
              size="md"
              showLabel
            />
          </Row>
        </Card>

        {/* Kanban Board */}
        <Row
          gap="var(--ggui-spacing-4)"
          align="start"
        >
          {props.columns.map((column) => {
            const columnTasks = tasks.filter((t) => t.column === column.id);
            const taskCount = columnTasks.length;

            return (
              <Box
                key={column.id}
                style={{
                  minWidth: 'var(--ggui-spacing-12)',
                  width: 'var(--ggui-spacing-12)',
                  display: 'flex',
                  flexDirection: 'column',
                }}
                <Stack gap="var(--ggui-spacing-3)" align="stretch">
                  {/* Column Header */}
                  <Box
                    padding="var(--ggui-spacing-3)"
                    background="var(--ggui-color-surfaceVariant)"
                    borderRadius="var(--ggui-shape-radius-md)"
                  >
                    <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                      <Stack gap="var(--ggui-spacing-1)">
                        <Heading level={4} color="var(--ggui-color-onSurfaceVariant)" size="sm">
                          {column.name}
                        </Heading>
                        <Badge variant="default" size="sm" pill>
                          {taskCount}
                        </Badge>
                      </Stack>
                    </Row>
                  </Box>

                  {/* Task List */}
                  <Stack
                    gap="var(--ggui-spacing-2)"
                    align="stretch"
                    style={{
                      flex: '1',
                      minHeight: 'var(--ggui-spacing-12)',
                      overflowY: 'auto',
                    }}
                    {columnTasks.length === 0 && !showAddFormColumn && (
                      <Box padding="var(--ggui-spacing-6)" align="center">
                        <Text
                          variant="caption"
                          color="var(--ggui-color-onSurfaceVariant)"
                          align="center"
                        >
                          No tasks
                        </Text>
                      </Box>
                    )}
                    {columnTasks.map((task) => (
                      <TaskCard
                        key={task.id}
                        task={task}
                        columns={props.columns}
                        onMove={handleMoveTask}
                        onEdit={handleEditTaskStart}
                        isEditing={editingTaskId === task.id}
                        editTitle={editingTaskId === task.id ? editingTitle : ''}
                        onEditChange={setEditingTitle}
                        onEditSave={handleEditTaskSave}
                        onEditCancel={handleEditTaskCancel}
                      />
                    ))}
                  </Stack>

                  {/* Add Task Form or Button */}
                    <Card padding="var(--ggui-spacing-3)" border background="var(--ggui-color-surface)">
                      <Stack gap="var(--ggui-spacing-3)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter') handleAddTask(column.id || '');
                            if (e.key === 'Escape') setShowAddFormColumn(null);
                          }}
                          placeholder="Enter task title"
                          size="sm"
                          autoFocus
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={setNewTaskPriority}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Row gap="var(--ggui-spacing-2)" justify="end">
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => setShowAddFormColumn(null)}
                          >
                            Cancel
                          </Button>
                          <Button
                            size="sm"
                            variant="primary"
                            onClick={() => handleAddTask(column.id || '')}
                          >
                            Add Task
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="outline"
                      size="sm"
                      fullWidth
                      onClick={() => setShowAddFormColumn(column.id || '')}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

