// Helper component for element cell
function ElementCell({ element, isSelected, onClick }: { element: Props['elements'][0]; isSelected: boolean; onClick: () => void }) {
  if (!element.symbol || !element.row || !element.col) return null;

  const getCategoryColor = (category?: string): string => {
    const colors: Record<string, string> = {
      'alkali-metal': 'var(--ggui-color-error-100)',
      'alkaline-earth-metal': 'var(--ggui-color-warning-100)',
      'transition-metal': 'var(--ggui-color-primary-100)',
      'post-transition-metal': 'var(--ggui-color-info-100)',
      'nonmetal': 'var(--ggui-color-success-100)',
      'halogen': 'var(--ggui-color-warning-200)',
      'noble-gas': 'var(--ggui-color-primary-200)',
      'lanthanide': 'var(--ggui-color-success-200)',
      'actinide': 'var(--ggui-color-error-200)',
      'metalloid': 'var(--ggui-color-info-200)',
    };
    return colors[category || ''] || 'var(--ggui-color-surfaceVariant)';
  };

  return (
    <Box
      as={Clickable}
      onClick={onClick}
      padding="var(--ggui-spacing-2)"
