export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [messages, setMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // Append incoming messages from stream
  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Determine if anyone else is typing
  const isTyping = typing.latest?.active && typing.latest?.sender !== props.currentUser;

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      // Add own message to list immediately
      setMessages((prev) => [...prev, { sender: props.currentUser, text: inputValue, timestamp }]);
      setInputValue('');
    }
  }, [inputValue, sendMessage, props.currentUser]);

  // Handle Enter key in input
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Format timestamp to readable time
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    messages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        groups.push({ sender: msg.sender, messages: [msg] });
      }
    });
    return groups;
  }, [messages]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="0" radius="lg" border={true}>
        <Stack gap="0" direction="vertical">
          {/* Header */}
          <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-container)" borderRadius="var(--ggui-shape-radius-lg) var(--ggui-shape-radius-lg) 0 0">
            <Row justify="between" align="center">
