              </Stack>
              <Badge variant="primary" size="md">{props.participantCount} participants</Badge>
            </Row>
          </Box>

          <Divider orientation="horizontal" margin="0" color="var(--ggui-color-outline)" />

          {/* Message List */}
          {/* Message List */}
          <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)" style={{ minHeight: '400px', maxHeight: '500px', overflowY: 'auto' }}>
            <Stack gap="var(--ggui-spacing-4)" direction="vertical" align="stretch">
              {groupedMessages.length === 0 ? (
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center" style={{ padding: 'var(--ggui-spacing-6)' }}>No messages yet</Text>
              ) : (
                groupedMessages.map((group, idx) => {
                  const isCurrentUser = group.sender === props.currentUser;
                  return (
                    <Stack
                      key={idx}
                      gap="var(--ggui-spacing-2)"
                      direction="vertical"
                      align={isCurrentUser ? 'end' : 'start'}
                      role="region"
                      aria-label={`Messages from ${group.sender || 'unknown'}`}
                    >
                      {group.sender && (
                        <Text variant="label" weight="semibold" color="var(--ggui-color-onSurfaceVariant)" style={{ paddingLeft: 'var(--ggui-spacing-2)' }}>
                          {group.sender}
                        </Text>
                      )}
                      {group.messages.map((msg, msgIdx) => (
                        <Box
                          key={msgIdx}
                          padding="var(--ggui-spacing-3)"
                          background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                          borderRadius="var(--ggui-shape-radius-md)"
                          style={{ maxWidth: '70%' }}
                          role="article"
                          aria-label={`Message from ${msg.sender || 'unknown'} at ${formatTime(msg.timestamp)}`}
                        >
                          <Text
                            variant="body"
                            color={isCurrentUser ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-onSurface)'}
                          >
                            {msg.text}
                          </Text>
                          <Text
                            variant="caption"
                            color={isCurrentUser ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-onSurfaceVariant)'}
                            style={{ marginTop: 'var(--ggui-spacing-1)', opacity: isCurrentUser ? 0.7 : 1 }}
                            aria-label={`Sent at ${formatTime(msg.timestamp)}`}
                          >
                            {formatTime(msg.timestamp)}
                          </Text>
                        </Box>
                      ))}
                    </Stack>
                  );
                })
              )}
              {isTyping && (
                <Box
                  padding="var(--ggui-spacing-2)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
