            </Stack>
          </Box>

          <Divider orientation="horizontal" margin="0" color="var(--ggui-color-outline)" />

          {/* Input Area */}
          <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)">
            <Row gap="var(--ggui-spacing-2)" align="center" justify="start">
              <Input
                label="Message"
