              <Alert variant="info" title="No forecast data">
                Forecast information is currently unavailable.
              </Alert>
            ) : (
              <Stack gap="var(--ggui-spacing-4)">
                <Row gap="var(--ggui-spacing-2)" wrap>
                  {safeForecast.map((item, index) => {
