import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });
  const [submitted, setSubmitted] = useState(false);

  const emailIsValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = useMemo(() => {
    if (!touched.name && !submitted) return '';
    return name.trim() ? '' : 'Name is required.';
  }, [name, touched.name, submitted]);
  const emailError = useMemo(() => {
    if (!touched.email && !submitted) return '';
    if (!email.trim()) return 'Email is required.';
    if (!emailIsValid) return 'Please enter a valid email address.';
    return '';
  }, [email, emailIsValid, touched.email, submitted]);

  const satisfactionOptions = useMemo(
    () =>
      (props.satisfactionLabels || []).map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`
      })),
    [props.satisfactionLabels]
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setSelectedFeatures((prev) => {
      if (checked) {
        return prev.includes(feature) ? prev : [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const canNext = useMemo(() => {
    if (step === 1) return Boolean(name.trim()) && emailIsValid;
    if (step === 2) return satisfactionOptions.length > 0 && Boolean(satisfaction);
    if (step === 3) return true;
    return false;
  }, [step, name, emailIsValid, satisfaction, satisfactionOptions.length]);

  const progressValue = useMemo(() => (step / 4) * 100, [step]);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
      setSubmitted(true);
      if (!name.trim() || !emailIsValid) return;
    }
    if (step === 2 && (!satisfaction || satisfactionOptions.length === 0)) return;
    if (step < 4) setStep((prev) => prev + 1);
  }, [step, name, emailIsValid, satisfaction]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep((prev) => prev - 1);
  }, [step]);

  const handleSubmit = useCallback(() => {
    if (!name.trim() || !emailIsValid || !satisfaction) return;
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features: selectedFeatures,
      comments: comments.trim()
    };
    submit(payload);
    const onSubmitMaybe = (props as unknown as { onSubmit?: (data: ActionSubmitPayload) => void }).onSubmit;
    if (typeof onSubmitMaybe === 'function') {
      onSubmitMaybe(payload);
    }
    setStep(1);
    setName('');
    setEmail('');
    setSatisfaction('');
    setSelectedFeatures([]);
    setComments('');
    setTouched({ name: false, email: false });
    setSubmitted(false);
  }, [name, email, emailIsValid, satisfaction, selectedFeatures, comments, submit, props]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Multi-step Survey</Heading>
              <Badge variant="primary">Step {step} of 4</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Complete each step to submit your survey response.
            </Text>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Your Information</Heading>
              <Input
                label="Name"
                required
                value={name}
                onChange={setName}
                onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
                placeholder="Enter your full name"
                error={nameError || undefined}
              />
              <Input
                label="Email"
                required
                type="email"
                value={email}
                onChange={setEmail}
                onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
                placeholder="you@example.com"
                error={emailError || undefined}
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Satisfaction Rating</Heading>
              {satisfactionOptions.length === 0 ? (
                <Alert variant="warning" title="No satisfaction options available">
                  Satisfaction choices are currently unavailable. Please try again later.
                </Alert>
              ) : (
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  error={!satisfaction && submitted ? 'Please select a rating.' : undefined}
                />
              )}
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Feature Interests</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Select all features you are interested in.
              </Text>
              <Stack gap="var(--ggui-spacing-2)">
                {(props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={selectedFeatures.includes(feature)}
                    onChange={(checked) => toggleFeature(feature, checked)}
                  />
                ))}
              </Stack>
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Additional Comments & Review</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
                placeholder="Share any additional feedback..."
              />
              <Divider margin="var(--ggui-spacing-2)" />
              <Heading level={5}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label">Name</Text>
                  <Text>{name || '-'}</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label">Email</Text>
                  <Text>{email || '-'}</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label">Satisfaction</Text>
                  <Text>
                    {satisfaction
                      ? `${satisfaction} - ${(props.satisfactionLabels || [])[Number(satisfaction) - 1] || ''}`
                      : '-'}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label">Feature Interests</Text>
                  <Text color="var(--ggui-color-onSurfaceVariant)">
                    {selectedFeatures.length ? selectedFeatures.join(', ') : 'None selected'}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label">Comments</Text>
                  <Text color="var(--ggui-color-onSurfaceVariant)">{comments.trim() || 'No comments provided'}</Text>
                </Stack>
              </Stack>
            </Stack>
          )}
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" disabled={step === 1} onClick={handleBack}>
            Back
          </Button>
          {step < 4 ? (
            <Button variant="primary" disabled={!canNext} onClick={handleNext}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>
              Submit Survey
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

