interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed
type TaskItem = { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };

const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

function getPriorityBadgeVariant(priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'success';
}

function normalizeTasks(input: Props['tasks']): TaskItem[] {
  return (input || []).map((task, index) => ({
    id: task.id || `task-${index}-${Date.now()}` ,
    title: task.title || 'Untitled Task',
    priority: task.priority || 'low',
    assignee: task.assignee || 'NA',
    column: task.column || 'todo',
    dueDate: task.dueDate,
  }));
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasksState, setTasksState] = useState<TaskItem[]>(() => normalizeTasks(props.tasks));
  const [addFormByColumn, setAddFormByColumn] = useState<Record<string, boolean>>({});
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    setTasksState(normalizeTasks(props.tasks));
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = taskChanged.latest.task;
    const incomingId = incoming.id || '';
    if (!incomingId) return;

    if (taskChanged.latest.action === 'delete') {
      setTasksState((prev) => prev.filter((task) => task.id !== incomingId));
      return;
    }

    const normalizedIncoming: TaskItem = {
      id: incomingId,
      title: incoming.title || 'Untitled Task',
      priority: incoming.priority || 'low',
      assignee: incoming.assignee || 'NA',
      column: incoming.column || 'todo',
      dueDate: incoming.dueDate,
    };

    setTasksState((prev) => {
      const index = prev.findIndex((task) => task.id === incomingId);
      if (index === -1) return [...prev, normalizedIncoming];
      const updated = [...prev];
      updated[index] = normalizedIncoming;
      return updated;
    });
  }, [taskChanged.latest]);

  const columnsWithFallback = useMemo(() => {
    if (props.columns && props.columns.length > 0) return props.columns;
    return [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' },
    ];
  }, [props.columns]);

  const completedColumnId = useMemo(() => {
    const doneColumn = columnsWithFallback.find((column) => (column.name || '').toLowerCase() === 'done') || columnsWithFallback.find((column) => (column.id || '').toLowerCase() === 'done');
    return doneColumn?.id || 'done';
  }, [columnsWithFallback]);

  const totalTasks = tasksState.length;
  const completedCount = tasksState.filter((task) => task.column === completedColumnId).length;

  const moveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: targetColumn } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  const startEdit = useCallback((task: TaskItem) => {
    setEditingTaskId(task.id);
    setEditingTitle(task.title);
  }, []);

  const saveEdit = useCallback((taskId: string) => {
    const nextTitle = editingTitle.trim();
    if (!nextTitle) return;
    const current = tasksState.find((task) => task.id === taskId);
    if (!current) return;
    const updatedTask: TaskItem = { ...current, title: nextTitle };
    setTasksState((prev) => prev.map((task) => (task.id === taskId ? updatedTask : task)));
    setEditingTaskId('');
    setEditingTitle('');
    taskUpdate({
      action: 'edit',
      taskId,
      data: {
        column: updatedTask.column,
        title: updatedTask.title,
        priority: updatedTask.priority,
        assignee: updatedTask.assignee,
        dueDate: updatedTask.dueDate || '',
      } as ActionTaskUpdatePayload['data'],
    });
  }, [editingTitle, taskUpdate, tasksState]);

  const cancelEdit = useCallback(() => {
    setEditingTaskId('');
    setEditingTitle('');
  }, []);

  const createTask = useCallback((columnId: string) => {
    const title = newTaskTitle.trim();
    if (!title) return;
    const newTask: TaskItem = {
      id: `task-${Date.now()}`,
      title,
      priority: newTaskPriority,
      assignee: 'NA',
      column: 'todo',
    };
    setTasksState((prev) => [...prev, newTask]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddFormByColumn((prev) => ({ ...prev, [columnId]: false }));
    taskUpdate({
      action: 'create',
      taskId: newTask.id,
      data: {
        column: newTask.column,
        title: newTask.title,
        priority: newTask.priority,
        assignee: newTask.assignee,
        dueDate: newTask.dueDate || '',
      } as ActionTaskUpdatePayload['data'],
    });
  }, [newTaskPriority, newTaskTitle, taskUpdate]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center" gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Kanban Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Real-time task collaboration
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        {taskChanged.latest ? (
          <Alert variant="info" title="Live update received">
            Team changes are synced in real time.
          </Alert>
        ) : null}

        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {columnsWithFallback.map((column) => {
            const columnId = column.id || '';
            const columnTasks = tasksState.filter((task) => task.column === columnId);
            return (
              <Card key={columnId || column.name} padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
                <Stack gap="var(--ggui-spacing-4)">
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name || 'Column'}</Heading>
                    <Badge variant="default">{columnTasks.length}</Badge>
                  </Row>

                  <Stack gap="var(--ggui-spacing-3)">
                    {columnTasks.length === 0 ? (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No tasks yet.
                      </Text>
                    ) : (
                      columnTasks.map((task) => {
                        const otherColumns = columnsWithFallback.filter((c) => c.id && c.id !== task.column);
                        return (
                          <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border radius="md">
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
                                {editingTaskId === task.id ? (
                                  <Input label="Edit task title" value={editingTitle} onChange={setEditingTitle} />
                                ) : (
                                  <Text
                                    as={Clickable}
                                    onDoubleClick={() => startEdit(task)}
                                    weight="medium"
                                    color="var(--ggui-color-onSurface)"
                                  >
                                    {task.title}
                                  </Text>
                                )}
                                <Button size="sm" variant="ghost" onClick={() => startEdit(task)}>Edit</Button>
                              </Row>

                              <Row gap="var(--ggui-spacing-2)" align="center">
                                <Badge variant={getPriorityBadgeVariant(task.priority)}>{task.priority}</Badge>
                                <Avatar name={task.assignee} size="xs" />
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {task.assignee}
                                </Text>
                              </Row>

                              {task.dueDate ? (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  Due: {task.dueDate}
                                </Text>
                              ) : null}

                              {editingTaskId === task.id ? (
                                <Row gap="var(--ggui-spacing-2)">
                                  <Button size="sm" variant="primary" onClick={() => saveEdit(task.id)}>Save</Button>
                                  <Button size="sm" variant="ghost" onClick={cancelEdit}>Cancel</Button>
                                </Row>
                              ) : null}

                              <Select
                                label="Move task"
                                value={task.column}
                                onChange={(value) => moveTask(task.id, value)}
                                options={columnsWithFallback.filter((c) => c.id).map((c) => ({ value: c.id || '', label: c.name || c.id || '' }))}
                              />

                              <Row gap="var(--ggui-spacing-2)" wrap>
                                {otherColumns.map((target) => (
                                  <Button
                                    key={target.id}
                                    size="sm"
                                    variant="outline"
                                    onClick={() => moveTask(task.id, target.id || '')}
                                  >
                                    Move to {target.name || target.id}
                                  </Button>
                                ))}
                              </Row>
                            </Stack>
                          </Card>
                        );
                      })
                    )}
                  </Stack>

                  {addFormByColumn[columnId] ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="none" border radius="md">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(value) => setNewTaskPriority(value as 'low' | 'medium' | 'high')}
                          options={PRIORITY_OPTIONS}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button variant="primary" size="sm" onClick={() => createTask(columnId)}>Create</Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => {
                              setAddFormByColumn((prev) => ({ ...prev, [columnId]: false }));
                              setNewTaskTitle('');
                              setNewTaskPriority('medium');
                            }}
                          >
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : null}

                  <Button
                    variant="secondary"
                    onClick={() => setAddFormByColumn((prev) => ({ ...prev, [columnId]: true }))}
                  >
                    Add Task
                  </Button>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>

  );
}

