}





// Place helper components here if needed
const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100)',
  'alkaline earth metal': 'var(--ggui-color-warning-100)',
  'transition metal': 'var(--ggui-color-primary-100)',
  'post-transition metal': 'var(--ggui-color-info-100)',
  metalloid: 'var(--ggui-color-success-100)',
  nonmetal: 'var(--ggui-color-surfaceVariant)',
  halogen: 'var(--ggui-color-warning-50)',
  'noble gas': 'var(--ggui-color-primary-50)',
  lanthanide: 'var(--ggui-color-success-50)',
  actinide: 'var(--ggui-color-error-50)',
};

function getCategoryColor(category?: string): string {
  if (!category) return 'var(--ggui-color-surfaceVariant)';
  const normalized = category.toLowerCase().replace(/-/g, ' ').trim();
  return CATEGORY_COLORS[normalized] || 'var(--ggui-color-surfaceVariant)';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedElements = useMemo(() => {
    return (props.elements || []).map((element) => ({
      atomicNumber: element.atomicNumber ?? 0,
      symbol: element.symbol ?? '',
      name: element.name ?? '',
      atomicWeight: element.atomicWeight ?? 0,
      category: element.category ?? 'unknown',
      row: element.row ?? 1,
      col: element.col ?? 1,
    }));
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const search = query.trim().toLowerCase();
    if (!search) return normalizedElements;
    return normalizedElements.filter((element) => {
      return element.name.toLowerCase().includes(search) || element.symbol.toLowerCase().includes(search);
    });
  }, [normalizedElements, query]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    normalizedElements.forEach((element) => {
      unique.add(element.category);
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [normalizedElements]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return normalizedElements.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [normalizedElements, selectedAtomicNumber]);

  useEffect(() => {
    if (selectedAtomicNumber === null && filteredElements.length > 0) {
      setSelectedAtomicNumber(filteredElements[0].atomicNumber);
    }
    if (selectedAtomicNumber !== null) {
      const stillVisible = filteredElements.some((element) => element.atomicNumber === selectedAtomicNumber);
      if (!stillVisible && filteredElements.length > 0) {
        setSelectedAtomicNumber(filteredElements[0].atomicNumber);
      }
      if (!stillVisible && filteredElements.length === 0) {
        setSelectedAtomicNumber(null);
      }
    }
  }, [filteredElements, selectedAtomicNumber]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements by name or symbol"
          value={query}
          onChange={setQuery}
          placeholder="e.g., Oxygen or O"
        />

        {normalizedElements.length === 0 ? (
          <Alert variant="info" title="No data available">
            No elements were provided in props.elements.
          </Alert>
        ) : (
          <Card padding="var(--ggui-spacing-4)" border shadow="sm">
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-2)',
                overflowX: 'auto',
                padding: 'var(--ggui-spacing-2)',
                background: 'var(--ggui-color-surface)',
              }}
            >
              {filteredElements.map((element) => {
                const isSelected = selectedElement?.atomicNumber === element.atomicNumber;
                return (
                  <Card
                    key={element.atomicNumber}
                    as={Clickable}
                    onClick={() => setSelectedAtomicNumber(element.atomicNumber)}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter' || event.key === ' ') {
                        event.preventDefault();
                        setSelectedAtomicNumber(element.atomicNumber);
                      }
                    }}
                    aria-label={`${element.name}, atomic number ${element.atomicNumber}`}
                    role="button"
                    tabIndex={0}
                    padding="var(--ggui-spacing-2)"
                    radius="md"
                    border
                    shadow="none"
                    hoverStyle={{
                      boxShadow: 'var(--ggui-shape-shadow-sm)',
                      opacity: 0.95,
                    }}
                    style={{
                      gridColumn: element.col,
                      gridRow: element.row,
                      minHeight: 'var(--ggui-spacing-12)',
                      background: getCategoryColor(element.category),
                      borderColor: isSelected ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                      outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : 'none',
                      outlineOffset: '2px',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {element.atomicNumber}
                      </Text>
                      <Text variant="bodyLarge" weight="bold" align="center">
                        {element.symbol}
                      </Text>
                    </Stack>
                  </Card>
                );
              })}
            </Box>
          </Card>
        )}

        {normalizedElements.length > 0 && filteredElements.length === 0 && (
          <Alert variant="warning" title="No matching elements">
            Try another search term. Filtering checks name and symbol.
          </Alert>
        )}

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text is="span" weight="semibold">Name:</Text> {selectedElement.name}</Text>
                <Text><Text is="span" weight="semibold">Symbol:</Text> {selectedElement.symbol}</Text>
                <Text><Text is="span" weight="semibold">Atomic Number:</Text> {selectedElement.atomicNumber}</Text>
                <Text><Text is="span" weight="semibold">Atomic Weight:</Text> {selectedElement.atomicWeight}</Text>
                <Text><Text is="span" weight="semibold">Category:</Text> {selectedElement.category}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Select an element to see details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Legend</Heading>
            <Row gap="var(--ggui-spacing-2)" wrap>
              {categories.map((category) => (
                <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    aria-hidden="true"
                    style={{
                      width: 'var(--ggui-spacing-3)',
                      height: 'var(--ggui-spacing-3)',
                      borderRadius: 'var(--ggui-shape-radius-sm)',
                      border: '1px solid var(--ggui-color-outline)',
                      background: getCategoryColor(category),
                    }}
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

