interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed

function getCurrencySymbol(currency?: string): string {
  if (!currency) return '$';
  const upper = currency.toUpperCase();
  const map: Record<string, string> = {
    USD: '$',
    EUR: '€',
    GBP: '£',
    JPY: '¥',
    INR: '₹',
    AUD: 'A$',
    CAD: 'C$',
  };
  return map[upper] ?? `${upper} `;
}

function renderStars(rating?: number) {
  const safeRating = Math.max(0, Math.min(5, Math.round(rating ?? 0)));
  return (
    <Row gap="var(--ggui-spacing-1)">
      {Array.from({ length: 5 }).map((_, index) => (
        <Text
          key={`star-${index}`}
          is="span"
          color={index < safeRating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        >
          ★
        </Text>
      ))}
    </Row>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState('description');
  const [quantity, setQuantity] = useState(1);

  const safeStock = Math.max(0, props.product?.stock ?? 0);
  const maxQuantity = safeStock;
  const isOutOfStock = safeStock <= 0;
  const isLowStock = safeStock > 0 && safeStock <= 5;
  const safePrice = props.product?.price ?? 0;
  const currencySymbol = getCurrencySymbol(props.product?.currency);
  const formattedPrice = `${currencySymbol}${safePrice.toFixed(2)}`;

  useEffect(() => {
    if (isOutOfStock) {
      setQuantity(1);
      return;
    }
    setQuantity((prev) => Math.min(Math.max(1, prev), maxQuantity));
  }, [maxQuantity, isOutOfStock]);

  const normalizedSpecifications = useMemo(() => {
    return (props.product?.specifications ?? []).map((item, index) => {
      if (item && typeof item === 'object' && !Array.isArray(item)) {
        const key = String((item as Record<string, unknown>).key ?? (item as Record<string, unknown>).name ?? `Spec ${index + 1}`);
        const value = String((item as Record<string, unknown>).value ?? (item as Record<string, unknown>).detail ?? '—');
        return { key, value };
      }
      return { key: `Spec ${index + 1}`, value: String(item ?? '—') };
    });
  }, [props.product?.specifications]);

  const normalizedReviews = useMemo(() => {
    return (props.product?.reviews ?? []).map((item, index) => {
      const obj = item && typeof item === 'object' ? (item as Record<string, unknown>) : {};
      return {
        id: String(obj.id ?? `review-${index}`),
        author: String(obj.author ?? obj.name ?? 'Anonymous'),
        rating: Math.max(0, Math.min(5, Number(obj.rating ?? 0))),
        text: String(obj.text ?? obj.comment ?? 'No review text provided.'),
        date: String(obj.date ?? obj.createdAt ?? 'Date unavailable'),
      };
    });
  }, [props.product?.reviews]);

  const handleDecrement = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const handleIncrement = useCallback(() => {
    setQuantity((prev) => Math.min(maxQuantity, prev + 1));
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (!props.product?.id || isOutOfStock) return;
    addToCart({ productId: props.product.id, quantity });
  }, [addToCart, props.product?.id, quantity, isOutOfStock]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Row gap="var(--ggui-spacing-6)" wrap>
            <Box
              background="var(--ggui-color-primary-100)"
              borderRadius="var(--ggui-shape-radius-lg)"
              padding="var(--ggui-spacing-8)"
            >
              <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                <Icon name="image" color="var(--ggui-color-primary-600)" size={32} />
                <Text weight="semibold" align="center" color="var(--ggui-color-primary-800)">
                  {props.product?.name ?? 'Unnamed Product'}
                </Text>
              </Stack>
            </Box>

            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={2}>{props.product?.name ?? 'Unnamed Product'}</Heading>
              <Text size="xl" weight="bold" color="var(--ggui-color-primary-700)">
                {formattedPrice}
              </Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                {renderStars(props.product?.rating)}
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  ({props.product?.reviewCount ?? normalizedReviews.length} reviews)
                </Text>
              </Row>
              <Row>
                <Badge variant={isLowStock ? 'warning' : 'success'}>
                  {isLowStock ? 'Low Stock' : 'In Stock'}
                </Badge>
              </Row>
            </Stack>
          </Row>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Text color="var(--ggui-color-onSurfaceVariant)">
                    {props.product?.description ?? 'No description available.'}
                  </Text>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: normalizedSpecifications.length > 0 ? (
                  <Table
                    columns={[
                      { key: 'key', header: 'Specification' },
                      { key: 'value', header: 'Value' },
                    ]}
                    data={normalizedSpecifications}
                    bordered
                  />
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: normalizedReviews.length > 0 ? (
                  <Stack gap="var(--ggui-spacing-4)">
                    {normalizedReviews.map((review) => (
                      <Card key={review.id} padding="var(--ggui-spacing-4)" shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Row justify="between" align="center">
                            <Text weight="semibold">{review.author}</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date}</Text>
                          </Row>
                          {renderStars(review.rating)}
                          <Text color="var(--ggui-color-onSurfaceVariant)">{review.text}</Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>
                ),
              },
            ]}
          />
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Purchase</Heading>
            <Row gap="var(--ggui-spacing-3)" align="center" wrap>
              <Text variant="label">Quantity</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  onClick={handleDecrement}
                  disabled={quantity <= 1 || isOutOfStock}
                  aria-label="Decrease quantity"
                >
                  -
                </Button>
                <Input
                  label="Quantity"
                  type="number"
                  value={String(quantity)}
                  onChange={() => {}}
                  disabled
                />
                <Button
                  variant="outline"
                  onClick={handleIncrement}
                  disabled={quantity >= maxQuantity || isOutOfStock}
                  aria-label="Increase quantity"
                >
                  +
                </Button>
              </Row>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {safeStock} items available
              </Text>
              <Spacer size="flex" />
              <Button variant="primary" onClick={handleAddToCart} disabled={isOutOfStock || !props.product?.id}>
                Add to Cart
              </Button>
            </Row>

            {isOutOfStock && (
              <Alert variant="warning" title="Out of stock">
                This product is currently unavailable.
              </Alert>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

