import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Place helper components here if needed
const formatCurrency = (value: number) => `$${value.toFixed(2)}`;
const formatSigned = (value: number) => `${value >= 0 ? '+' : ''}${value.toFixed(2)}`;
const formatPercent = (value: number) => `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;

const toMap = (stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>) => {
  const map = new Map<string, { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>();
  stocks.forEach((stock) => {
    if (stock.symbol) {
      map.set(stock.symbol, stock);
    }
  });
  return map;
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [stocksBySymbol, setStocksBySymbol] = useState<Map<string, { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(() => toMap(props.stocks || []));
  const [lastUpdated, setLastUpdated] = useState<string>(() => new Date().toLocaleTimeString());
  const [flashingSymbols, setFlashingSymbols] = useState<Record<string, boolean>>({});
  const flashTimersRef = useRef<Record<string, number>>({});

  useEffect(() => {
    setStocksBySymbol(toMap(props.stocks || []));
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setLastUpdated(new Date().toLocaleTimeString());
    }, 1000);

    return () => {
      clearInterval(timer);
    };
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }

    const symbol = priceUpdate.latest.symbol;
    setStocksBySymbol((prev) => {
      const next = new Map(prev);
      const existing = next.get(symbol) || { symbol, name: undefined, price: undefined, change: undefined, changePercent: undefined };
      next.set(symbol, {
        ...existing,
        symbol,
        price: priceUpdate.latest?.price ?? existing.price,
        change: priceUpdate.latest?.change ?? existing.change,
        changePercent: priceUpdate.latest?.changePercent ?? existing.changePercent,
      });
      return next;
    });

    setLastUpdated(new Date().toLocaleTimeString());
    setFlashingSymbols((prev) => ({ ...prev, [symbol]: true }));

    if (flashTimersRef.current[symbol]) {
      clearTimeout(flashTimersRef.current[symbol]);
    }
    flashTimersRef.current[symbol] = setTimeout(() => {
      setFlashingSymbols((prev) => ({ ...prev, [symbol]: false }));
    }, 700) as unknown as number;
  }, [priceUpdate.latest]);

  useEffect(() => {
    return () => {
      Object.values(flashTimersRef.current).forEach((timerId) => clearTimeout(timerId));
    };
  }, []);

  const stocksList = useMemo(() => Array.from(stocksBySymbol.values()), [stocksBySymbol]);
  const statusText = marketStatus.latest?.status || 'open';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-4)"
          border
          radius="lg"
          shadow="sm"
        >
          <Row align="center" justify="between">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Market Watch
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {lastUpdated}
              </Text>
            </Stack>
            <Badge variant={statusText === 'open' ? 'success' : statusText === 'closed' ? 'error' : 'warning'}>
              {statusText}
            </Badge>
          </Row>
        </Card>

        {stocksList.length === 0 ? (
          <Alert variant="info" title="No stocks available">
            Waiting for stock data to display.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocksList.map((stock, index) => {
              const symbol = stock.symbol || `stock-${index}`;
              const changeValue = stock.change ?? 0;
              const changePercentValue = stock.changePercent ?? 0;
              const isPositive = changeValue >= 0;
              const accentColor = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';

              return (
                <Card
                  key={symbol}
                  padding="var(--ggui-spacing-4)"
                  border
                  radius="lg"
                  shadow="sm"
                >
                  <Box
                    style={{
                      border: `1px solid ${accentColor}`,
                      borderRadius: 'var(--ggui-shape-radius-md)',
                      padding: 'var(--ggui-spacing-4)',
                      background: 'var(--ggui-color-surfaceVariant)',
                      animation: flashingSymbols[symbol] ? 'ggui-flash 600ms ease-out' : 'none',
                      transition: 'border-color 200ms ease-in-out, background-color 200ms ease-in-out',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Heading level={3} color="var(--ggui-color-onSurface)">
                        {stock.symbol || '—'}
                      </Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name || 'Unknown Company'}
                      </Text>
                      <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                        {formatCurrency(stock.price ?? 0)}
                      </Text>
                      <Row align="center" gap="var(--ggui-spacing-2)">
                        <Text variant="label" color={accentColor}>
                          {formatSigned(changeValue)}
                        </Text>
                        <Text variant="label" color={accentColor}>
                          {isPositive ? '▲' : '▼'} {formatPercent(changePercentValue)}
                        </Text>
                      </Row>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed
const AVATAR_FALLBACKS = ['😀', '😎', '🚀', '🌟'];
const ROLE_FALLBACKS = ['Developer', 'Designer', 'Manager', 'Other'];
const THEME_OPTIONS = ['light', 'dark'];

const isValidEmail = (email: string): boolean => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const availableAvatars = useMemo(() => {
    if (props.avatarOptions && props.avatarOptions.length > 0) return props.avatarOptions;
    return AVATAR_FALLBACKS;
  }, [props.avatarOptions]);

  const availableRoles = useMemo(() => {
    if (props.roleOptions && props.roleOptions.length > 0) return props.roleOptions;
    return ROLE_FALLBACKS;
  }, [props.roleOptions]);

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar ?? (availableAvatars[0] ?? AVATAR_FALLBACKS[0]));
  const [role, setRole] = useState(props.initialProfile?.role ?? (availableRoles[0] ?? ROLE_FALLBACKS[0]));
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(
    props.initialProfile?.theme && THEME_OPTIONS.includes(props.initialProfile.theme) ? props.initialProfile.theme : 'light',
  );
  const [showError, setShowError] = useState(false);

  useEffect(() => {
    if (!avatar && availableAvatars.length > 0) {
      setAvatar(availableAvatars[0]);
    }
  }, [avatar, availableAvatars]);

  useEffect(() => {
    if (!role && availableRoles.length > 0) {
      setRole(availableRoles[0]);
    }
  }, [role, availableRoles]);

  const emailError = useMemo(() => {
    if (!email.trim()) return 'Email is required';
    if (!isValidEmail(email)) return 'Please enter a valid email address';
    return '';
  }, [email]);

  const isStep1Valid = useMemo(() => {
    return name.trim().length > 0 && emailError === '' && avatar.trim().length > 0;
  }, [name, emailError, avatar]);

  const canGoNext = useMemo(() => {
    if (step === 1) return isStep1Valid;
    return step < 3;
  }, [step, isStep1Valid]);

  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const handleNext = useCallback(() => {
    if (step === 1 && !isStep1Valid) {
      setShowError(true);
      return;
    }
    setShowError(false);
    setStep((current) => Math.min(3, current + 1));
  }, [step, isStep1Valid]);

  const handleBack = useCallback(() => {
    setShowError(false);
    setStep((current) => Math.max(1, current - 1));
  }, []);

  const handleComplete = useCallback(() => {
    if (!isStep1Valid) {
      setStep(1);
      setShowError(true);
      return;
    }
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [isStep1Valid, complete, name, email, avatar, role, emailNotifications, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Row gap="var(--ggui-spacing-2)" wrap>
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        {showError && step === 1 && (
          <Alert variant="error" title="Please complete required fields">
            Name and a valid email are required before continuing.
          </Alert>
        )}

        <Card
          padding="var(--ggui-spacing-6)"
          border
          shadow="md"
        >
          <Box
            key={step}
            style={{
              animation: 'ggui-slideInUp var(--ggui-motion-duration-normal) var(--ggui-motion-ease-out)',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Step 1: Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={showError && !name.trim() ? 'Name is required' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={showError || email.trim() ? emailError || undefined : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" is="label" id="avatar-group-label">Choose your avatar</Text>
                  <Box
                    role="radiogroup"
                    aria-labelledby="avatar-group-label"
                    onKeyDown={(event) => {
                      const currentIndex = availableAvatars.findIndex((item) => item === avatar);
                      if (event.key === 'ArrowRight' || event.key === 'ArrowDown') {
                        event.preventDefault();
                        const nextIndex = (currentIndex + 1) % availableAvatars.length;
                        setAvatar(availableAvatars[nextIndex]);
                      }
                      if (event.key === 'ArrowLeft' || event.key === 'ArrowUp') {
                        event.preventDefault();
                        const prevIndex = (currentIndex - 1 + availableAvatars.length) % availableAvatars.length;
                        setAvatar(availableAvatars[prevIndex]);
                      }
                    }}
                  >
                    <Row
                      gap="var(--ggui-spacing-2)"
                      wrap
                    >
                      <Card
                        key={emoji}
                        as={Clickable}
                        onClick={() => setAvatar(emoji)}
                        onKeyDown={(event) => {
                          if (event.key === 'Enter' || event.key === ' ') {
                            event.preventDefault();
                            setAvatar(emoji);
                          }
                        }}
                        padding="var(--ggui-spacing-3)"
                        border
                        radius="md"
                        shadow="none"
                        role="radio"
                        tabIndex={avatar === emoji ? 0 : -1}
                        aria-label={`Select avatar ${emoji}`}
                        aria-checked={avatar === emoji}
                        hoverStyle={{
                          background: 'var(--ggui-color-surfaceVariant)',
                          borderColor: 'var(--ggui-color-primary-400)',
                        }}
                        pressStyle={{
                          transform: 'var(--ggui-press-transform)',
                        }}
                        style={{
                          borderColor: avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === emoji ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                          outline: avatar === emoji ? '2px solid var(--ggui-color-primary-600)' : 'none',
                          outlineOffset: 'var(--ggui-spacing-1)',
                        }}
                      >
                        <Text align="center" size="2xl">
                          {emoji}
                        </Text>
                      </Card>
                    ))}
                    </Row>
                  </Box>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Step 2: Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={availableRoles.map((item) => ({ value: item, label: item }))}
                  placeholder="Select role"
                />
                <Toggle
                  label="Enable email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Current theme preference: {theme}
                </Text>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Step 3: Review &amp; Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between" align="center" gap="var(--ggui-spacing-2)"><Text variant="label">Name</Text><Text>{name || '—'}</Text></Row>
                    <Row justify="between" align="center" gap="var(--ggui-spacing-2)"><Text variant="label">Email</Text><Text>{email || '—'}</Text></Row>
                    <Row justify="between" align="center" gap="var(--ggui-spacing-2)"><Text variant="label">Avatar</Text><Text>{avatar || '—'}</Text></Row>
                    <Row justify="between" align="center" gap="var(--ggui-spacing-2)"><Text variant="label">Role</Text><Text>{role || '—'}</Text></Row>
                    <Row justify="between" align="center" gap="var(--ggui-spacing-2)"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between" align="center" gap="var(--ggui-spacing-2)"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Need changes? Use Go Back to edit your details.
                </Text>
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" onClick={handleBack} disabled={step === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 && (
              <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                Next
              </Button>
            )}
            {step === 3 && (
              <>
                <Button variant="outline" onClick={handleBack}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete}>
                  Complete Setup
                </Button>
              </>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>

  );
}
